function fix(t) {
  if (!t) return t;
  return t.replace(/(?<!\\)&(?![a-zA-Z])/g,'\\&')
    .replace(/([^\\])%(?![\s]*$)/gm,'$1\\%')
    .replace(/(?<!\\)#(?![a-fA-F0-9]{6}\b)/g,'\\#')
    .replace(/[\u2018\u2019]/g,"'")
    .replace(/[\u201C\u201D]/g,'"')
    .replace(/\u2014/g,'---').replace(/\u2013/g,'--')
    .replace(/[\u200B-\u200D\uFEFF]/g,'');
}
function ext(tag, text) {
  const m = text.match(new RegExp('<'+tag+'>[\\s\\S]*?</'+tag+'>'));
  if (!m) return null;
  return m[0].replace(new RegExp('<'+tag+'>'),'').replace(new RegExp('</'+tag+'>'),'')
    .replace(/^```latex\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
}
const raw  = $input.first().json?.choices?.[0]?.message?.content || '';
const data = $('Collect All Candidates').first().json;
const sections = {
  summary:    ext('SUMMARY', raw),
  experience: fix(ext('EXPERIENCE', raw)),
  skills:     fix(ext('SKILLS', raw)),
  projects:   fix(ext('PROJECTS', raw))
};
for (const [k, v] of Object.entries(sections)) {
  if (!v || v.trim().length < 20) {
    const fb = data.candidates[k]?.[0] || '';
    sections[k] = ['experience','skills','projects'].includes(k) ? fix(fb) : fb;
  }
}
return [{ json: { ...data, sections } }];

const verifyResp = $input.first().json;
