try {
  let raw = verifyResp.choices?.[0]?.message?.content || verifyResp.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  raw = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
  audit = JSON.parse(raw);
} catch(e) {
  audit = { total_violations: 0, verdict: 'CLEAN', experience_violations: [], project_violations: [], summary_violations: [] };
}
const sections = { ...judgeData.sections };
const revertedBullets = [];
for (const v of (audit.experience_violations || [])) {
  if (v.original_bullet && v.original_bullet !== 'null') {
    const esc = v.synthesised_bullet.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const nb  = v.original_bullet.replace(/&/g,'\\&').replace(/%/g,'\\%');
    sections.experience = sections.experience.replace(new RegExp(esc,'g'), nb);
    revertedBullets.push({ section:'experience', type:v.violation_type, reverted:v.synthesised_bullet.substring(0,80) });
  }
}
for (const v of (audit.project_violations || [])) {
  if (v.original_text && v.original_text !== 'null') {
    const esc = v.synthesised_bullet.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const nb  = v.original_text.replace(/&/g,'\\&').replace(/%/g,'\\%');
    sections.projects = sections.projects.replace(new RegExp(esc,'g'), nb);
    revertedBullets.push({ section:'projects', type:v.violation_type, reverted:v.synthesised_bullet.substring(0,80) });
  }
}
const auditHTML = audit.verdict === 'CLEAN'
  ? "<div style='background:#d4edda;border:1px solid #28a745;padding:10px;border-radius:6px;margin:8px 0'><strong>Ground truth check passed</strong> — no hallucinated content detected.</div>"
  : "<div style='background:#fff3cd;border:1px solid #ffc107;padding:10px;border-radius:6px;margin:8px 0'><strong>" + audit.total_violations + " accuracy issue(s) auto-corrected</strong><br/><ul>" + revertedBullets.map(r=>'<li>['+r.section+'/'+r.type+'] '+r.reverted+'</li>').join('') + "</ul></div>";
return [{ json: { ...judgeData, sections, audit, auditHTML, revertedBullets } }];

