function validate(name, content, rules) {
  const errors=[], warnings=[];
  if (!content || content.trim().length===0) { errors.push(name+': empty'); return {isValid:false,errors,warnings}; }
  const ph = content.match(/WRITE_[A-Z_]+|\[BULLET[^\]]*\]|\[ITEMS[^\]]*\]/g);
  if (ph) errors.push(name+': unfilled placeholders');
  if (rules.forbidDoc) {
    if (content.includes('\\documentclass')) errors.push(name+': has documentclass');
    if (content.includes('\\begin{document}')) errors.push(name+': has begin document');
  }
  if (rules.itemize) {
    const b=(content.match(/\\begin\{itemize\}/g)||[]).length;
    const e=(content.match(/\\end\{itemize\}/g)||[]).length;
    if (b===0) errors.push(name+': no itemize');
    if (b!==e) errors.push(name+': unbalanced itemize ('+b+'/'+e+')');
  }
  if (rules.multicols) {
    const b=(content.match(/\\begin\{multicols\}/g)||[]).length;
    const e=(content.match(/\\end\{multicols\}/g)||[]).length;
    if (b<2) errors.push(name+': need 2 multicols, found '+b);
    if (b!==e) errors.push(name+': unbalanced multicols');
  }
  if (rules.locks) for (const l of rules.locks) if (!content.includes(l)) warnings.push(name+': lock missing: '+l);
  const wc = content.split(/\s+/).length;
